import{bQ as i,aL as a,u as t,G as n}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"哨兵模式","description":"","frontmatter":{},"headers":[],"relativePath":"05.Redis/06-哨兵模式.md","filePath":"05.Redis/06-哨兵模式.md","lastUpdated":null}'),e={name:"05.Redis/06-哨兵模式.md"};function l(p,s,h,d,r,k){return a(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="哨兵模式" tabindex="-1">哨兵模式 <a class="header-anchor" href="#哨兵模式" aria-label="Permalink to &quot;哨兵模式&quot;">​</a></h1><p>Redis Sentinel 是主从架构外面的一层&quot;观察者和调度者&quot;——一组 Sentinel 进程持续监控主库和从库，发现主库不可用后投票确认故障，再从从库中选一个提升为新主库，通知其他从库改挂新主。</p><p>Sentinel 解决的是主从的自动切换问题，不解决分片扩容问题。数据容量和写入压力仍然由单个主库承担。需要多主分片时看 Redis Cluster。</p><h2 id="一、sentinel-的部署结构" tabindex="-1">一、Sentinel 的部署结构 <a class="header-anchor" href="#一、sentinel-的部署结构" aria-label="Permalink to &quot;一、Sentinel 的部署结构&quot;">​</a></h2><p>Sentinel 进程和 Redis 进程是分开的——它监听独立的端口（默认 26379），使用独立的配置文件和 systemd unit。Sentinel 可以和 Redis 部署在同一台机器上，也可以分开部署。</p><p>至少需要 3 个 Sentinel 节点。Sentinel 需要投票达成共识（quorum）才能确认故障——1 个节点自身故障就可能误判，2 个节点出现网络分区时无法区分&quot;对方挂了&quot;和&quot;网络断了&quot;。3 个节点用奇数，投票不容易出现平局。</p><p>示例拓扑：</p><table tabindex="0"><thead><tr><th>角色</th><th>地址</th><th>Redis 端口</th><th>Sentinel 端口</th></tr></thead><tbody><tr><td>Redis master</td><td>192.168.10.11</td><td>6379</td><td>26379</td></tr><tr><td>Redis replica</td><td>192.168.10.129</td><td>6379</td><td>26379</td></tr><tr><td>Redis replica</td><td>192.168.10.130</td><td>6379</td><td>26379</td></tr></tbody></table><div class="mermaid-diagram" data-mermaid-code="flowchart%20TB%0A%20%20%20%20subgraph%20sentinels%5B%22Sentinel%20%E6%8A%95%E7%A5%A8%E7%BB%84%22%5D%0A%20%20%20%20%20%20%20%20s1%5B%22Sentinel%2001%3Cbr%2F%3E192.168.10.11%3A26379%22%5D%0A%20%20%20%20%20%20%20%20s2%5B%22Sentinel%2002%3Cbr%2F%3E192.168.10.129%3A26379%22%5D%0A%20%20%20%20%20%20%20%20s3%5B%22Sentinel%2003%3Cbr%2F%3E192.168.10.130%3A26379%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20master%5B%22Redis%20%E4%B8%BB%E5%BA%93%3Cbr%2F%3E192.168.10.11%3A6379%22%5D%0A%20%20%20%20r1%5B%22Redis%20%E4%BB%8E%E5%BA%93%3Cbr%2F%3E192.168.10.129%3A6379%22%5D%0A%20%20%20%20r2%5B%22Redis%20%E4%BB%8E%E5%BA%93%3Cbr%2F%3E192.168.10.130%3A6379%22%5D%0A%0A%20%20%20%20s1%20--%3E%20master%0A%20%20%20%20s2%20--%3E%20master%0A%20%20%20%20s3%20--%3E%20master%0A%20%20%20%20master%20--%3E%20r1%0A%20%20%20%20master%20--%3E%20r2%0A"></div><p>先配好 Redis 主从，再部署 Sentinel。Sentinel 的配置对象是&quot;已经存在的主从拓扑&quot;。</p><h2 id="二、sentinel-配置文件" tabindex="-1">二、Sentinel 配置文件 <a class="header-anchor" href="#二、sentinel-配置文件" aria-label="Permalink to &quot;二、Sentinel 配置文件&quot;">​</a></h2><p><code>sentinel.conf</code>：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>port 26379</span></span>
<span class="line"><span>daemonize no</span></span>
<span class="line"><span>supervised systemd</span></span>
<span class="line"><span>dir /data/redis-sentinel</span></span>
<span class="line"><span>logfile /var/log/redis/sentinel.log</span></span>
<span class="line"><span></span></span>
<span class="line"><span>sentinel monitor mymaster 192.168.10.11 6379 2</span></span>
<span class="line"><span>sentinel down-after-milliseconds mymaster 5000</span></span>
<span class="line"><span>sentinel failover-timeout mymaster 60000</span></span>
<span class="line"><span>sentinel parallel-syncs mymaster 1</span></span></code></pre></div><p>关键配置的含义：</p><ul><li><strong><code>sentinel monitor mymaster 192.168.10.11 6379 2</code></strong>：告诉 Sentinel 监控主库 <code>192.168.10.11:6379</code>，命名为 <code>mymaster</code>（这个名字会被客户端用来查询主库地址），最后的 <code>2</code> 是 quorum——至少 2 个 Sentinel 同意才算客观下线。</li><li><strong><code>down-after-milliseconds 5000</code></strong>：单个 Sentinel 在 5 秒内没有收到主库的正常响应，就把它标记为 SDOWN（主观下线）。</li><li><strong><code>failover-timeout 60000</code></strong>：故障转移各阶段的总超时时间。如果 60 秒内切换没完成，就放弃本次尝试。</li><li><strong><code>parallel-syncs 1</code></strong>：切换完成后，允许多少个从库同时并行同步新主。设为 1 表示一次只同步一个，避免新主同时给所有从库发 RDB 压力太大。</li></ul><p>如果 Redis 有密码：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sentinel auth-pass mymaster strong_password_here</span></span></code></pre></div><p>Sentinel 在运行过程中会自动重写 <code>sentinel.conf</code>，把发现的从库、其他 Sentinel 节点、当前主库状态写进去。所以 <code>sentinel.conf</code> 文件需要对 Redis 运行用户有写权限，且不要设置为只读。自动重写的内容是 Sentinel 的&quot;运行时记忆&quot;——重启后靠这些记录恢复对拓扑的认知。</p><h2 id="三、systemd-管理-sentinel" tabindex="-1">三、systemd 管理 Sentinel <a class="header-anchor" href="#三、systemd-管理-sentinel" aria-label="Permalink to &quot;三、systemd 管理 Sentinel&quot;">​</a></h2><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /etc/systemd/system/redis-sentinel.service</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[Unit]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=Redis Sentinel</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">After</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=network.target</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[Service]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=notify</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">User</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=redis</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Group</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=redis</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ExecStart</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/usr/local/redis/bin/redis-sentinel /etc/redis/sentinel.conf --supervised systemd</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Restart</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=on-failure</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RestartSec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=5</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LimitNOFILE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=100000</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[Install]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WantedBy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=multi-user.target</span></span></code></pre></div><p>启动：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> daemon-reload</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --now</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-sentinel</span></span></code></pre></div><h2 id="四、查看-sentinel-状态" tabindex="-1">四、查看 Sentinel 状态 <a class="header-anchor" href="#四、查看-sentinel-状态" aria-label="Permalink to &quot;四、查看 Sentinel 状态&quot;">​</a></h2><p>Sentinel 用 <code>redis-cli</code> 连接到它的端口（26379），用 <code>SENTINEL</code> 系列子命令管理：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 26379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PING</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看当前监控的主库</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 26379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SENTINEL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> master</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mymaster</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看从库列表</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 26379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SENTINEL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> replicas</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mymaster</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看其他 Sentinel 节点</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 26379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SENTINEL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sentinels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mymaster</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 获取当前主库的地址（客户端最常用的查询）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 26379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SENTINEL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get-master-addr-by-name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mymaster</span></span></code></pre></div><p><code>SENTINEL get-master-addr-by-name</code> 是客户端发现主库的核心命令。应用不写死主库 IP，而是通过 Sentinel 查询当前主库地址——切换后查询结果自动指向新主库。但前提是客户端的连接库（如 Jedis、Lettuce、redigo）支持 Sentinel 模式并正确配置了 Sentinel 地址列表。</p><h2 id="五、主观下线-sdown-和客观下线-odown" tabindex="-1">五、主观下线（SDOWN）和客观下线（ODOWN） <a class="header-anchor" href="#五、主观下线-sdown-和客观下线-odown" aria-label="Permalink to &quot;五、主观下线（SDOWN）和客观下线（ODOWN）&quot;">​</a></h2><p>Sentinel 判断故障分两层：</p><table tabindex="0"><thead><tr><th>状态</th><th>触发条件</th><th>含义</th></tr></thead><tbody><tr><td>SDOWN（主观下线）</td><td>单个 Sentinel 在 <code>down-after-milliseconds</code> 时间内没收到主库正常响应</td><td>单个 Sentinel 判定主库异常</td></tr><tr><td>ODOWN（客观下线）</td><td>达到 quorum 数量的 Sentinel 都报告 SDOWN</td><td>多个 Sentinel 达成故障判断</td></tr></tbody></table><p>只有进入 ODOWN 后，Sentinel 才会启动故障转移。这两个阶段的设计是为了防止单个 Sentinel 因为自身网络问题而误判主库故障。</p><p>quorum 值的选择：</p><ul><li>3 个 Sentinel，quorum = 2：任意 1 个出问题（宕机或网络分区），还有 2 个可以正常投票</li><li>5 个 Sentinel，quorum = 3：容忍 2 个出问题</li></ul><p>quorum 太低容易误判——比如网络抖动导致 2 个 Sentinel 暂时连不上主库；quorum 太高可能真的故障时凑不够票，切换迟迟不触发。</p><h2 id="六、故障转移的过程中做了什么" tabindex="-1">六、故障转移的过程中做了什么 <a class="header-anchor" href="#六、故障转移的过程中做了什么" aria-label="Permalink to &quot;六、故障转移的过程中做了什么&quot;">​</a></h2><p>主库被确认为 ODOWN 后：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20TD%0A%20%20%20%20odown%5B%22%E4%B8%BB%E5%BA%93%E8%BF%9B%E5%85%A5%20ODOWN%22%5D%20--%3E%20elect%5B%22Sentinel%20%E9%80%89%E4%B8%BE%20leader%22%5D%0A%20%20%20%20elect%20--%3E%20choose%5B%22leader%20%E9%80%89%E6%8B%A9%E6%95%B0%E6%8D%AE%E8%BE%83%E6%96%B0%E7%9A%84%E4%BB%8E%E5%BA%93%22%5D%0A%20%20%20%20choose%20--%3E%20promote%5B%22%E5%90%91%E7%9B%AE%E6%A0%87%E4%BB%8E%E5%BA%93%E5%8F%91%E9%80%81%3Cbr%2F%3EREPLICAOF%20NO%20ONE%22%5D%0A%20%20%20%20promote%20--%3E%20reconfig%5B%22%E9%80%9A%E7%9F%A5%E5%85%B6%E4%BB%96%E4%BB%8E%E5%BA%93%3Cbr%2F%3E%E6%94%B9%E4%B8%BA%E5%A4%8D%E5%88%B6%E6%96%B0%E4%B8%BB%E5%BA%93%22%5D%0A%20%20%20%20reconfig%20--%3E%20update%5B%22Sentinel%20%E6%9B%B4%E6%96%B0%E4%B8%BB%E5%BA%93%E5%9C%B0%E5%9D%80%22%5D%0A%20%20%20%20update%20--%3E%20client%5B%22%E5%AE%A2%E6%88%B7%E7%AB%AF%E6%9F%A5%E8%AF%A2%20mymaster%3Cbr%2F%3E%E8%8E%B7%E5%BE%97%E6%96%B0%E4%B8%BB%E5%BA%93%E5%9C%B0%E5%9D%80%22%5D%0A"></div><p>选主（第二步）时的权衡因素：</p><table tabindex="0"><thead><tr><th>因素</th><th>优先</th></tr></thead><tbody><tr><td>从库是否在线</td><td>下线的直接排除</td></tr><tr><td>复制偏移量</td><td>offset 越大越好，数据越新</td></tr><tr><td><code>replica-priority</code></td><td>值越小优先级越高，0 表示永不提升</td></tr><tr><td>运行 ID</td><td>以上都相同时按运行 ID 排序</td></tr></tbody></table><p>如果有一台从库只用于备份、不希望被提升为主库：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>replica-priority 0    # 这个从库永远不会被 Sentinel 提升为主库</span></span></code></pre></div><h2 id="七、手动触发切换" tabindex="-1">七、手动触发切换 <a class="header-anchor" href="#七、手动触发切换" aria-label="Permalink to &quot;七、手动触发切换&quot;">​</a></h2><p>维护窗口里（比如要重启主库所在机器），可以先手动触发一次平滑切换：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 26379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SENTINEL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> failover</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mymaster</span></span></code></pre></div><p>这会让 Sentinel 主动执行一次故障转移——原主库变成从库，选一个从库提升。和被动故障切换的区别是：旧主库在线的情况下可以平滑交接，不会有数据丢失。</p><p>手动切换后验证：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 确认新主库地址</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 26379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SENTINEL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get-master-addr-by-name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mymaster</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在新主库上做写入测试</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">新主库I</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">P</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:failover</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">date</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +%s)&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">新主库I</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">P</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:failover</span></span></code></pre></div><h2 id="八、客户端如何适配-sentinel" tabindex="-1">八、客户端如何适配 Sentinel <a class="header-anchor" href="#八、客户端如何适配-sentinel" aria-label="Permalink to &quot;八、客户端如何适配 Sentinel&quot;">​</a></h2><p>客户端不能写死主库 IP——写死的话 Sentinel 切换了，应用还连着旧地址。正确的接入方式：</p><table tabindex="0"><thead><tr><th>配置项</th><th>示例</th></tr></thead><tbody><tr><td>Sentinel 地址列表</td><td><code>192.168.10.11:26379</code>、<code>192.168.10.129:26379</code>、<code>192.168.10.130:26379</code></td></tr><tr><td>master 名称</td><td><code>mymaster</code></td></tr></tbody></table><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20app%5B%22%E5%AE%A2%E6%88%B7%E7%AB%AF%22%5D%20--%3E%20slist%5B%22Sentinel%20%E5%9C%B0%E5%9D%80%E5%88%97%E8%A1%A8%22%5D%0A%20%20%20%20slist%20--%3E%20sentinel%5B%22%E4%BB%BB%E6%84%8F%E5%8F%AF%E7%94%A8%20Sentinel%22%5D%0A%20%20%20%20sentinel%20--%3E%20query%5B%22%E6%9F%A5%E8%AF%A2%20mymaster%3Cbr%2F%3E%E5%BD%93%E5%89%8D%E4%B8%BB%E5%BA%93%E5%9C%B0%E5%9D%80%22%5D%0A%20%20%20%20query%20--%3E%20master%5B%22%E8%BF%9E%E6%8E%A5%20Redis%20%E4%B8%BB%E5%BA%93%22%5D%0A%20%20%20%20sentinel%20--%3E%20event%5B%22%E5%8F%91%E5%B8%83%E5%88%87%E6%8D%A2%E4%BA%8B%E4%BB%B6%22%5D%0A%20%20%20%20event%20--%3E%20reconnect%5B%22%E5%AE%A2%E6%88%B7%E7%AB%AF%E5%88%B7%E6%96%B0%E8%BF%9E%E6%8E%A5%3Cbr%2F%3E%E9%87%8D%E8%BF%9E%E6%96%B0%E4%B8%BB%E5%BA%93%22%5D%0A"></div><p>客户端要能处理&quot;查到的地址突然连不上&quot;的情况——更新主库地址后立即重连新主库，而不是一直重试旧地址。</p><h2 id="九、切换后常见的-看起来切换了但业务没好" tabindex="-1">九、切换后常见的&quot;看起来切换了但业务没好&quot; <a class="header-anchor" href="#九、切换后常见的-看起来切换了但业务没好" aria-label="Permalink to &quot;九、切换后常见的&quot;看起来切换了但业务没好&quot;&quot;">​</a></h2><p>Sentinel 报告切换成功，不等于业务恢复了。几个经常出问题的环节：</p><table tabindex="0"><thead><tr><th>问题</th><th>原因</th><th>怎么确认</th></tr></thead><tbody><tr><td>应用还连着旧主库</td><td>客户端直接写死了 IP</td><td>检查客户端配置是否使用 Sentinel</td></tr><tr><td>连接池没刷新</td><td>连接池里的旧连接还保留着</td><td>检查连接池是否在收到切换事件后重建连接</td></tr><tr><td>旧主库恢复后又写入</td><td>旧主库重启后没有加 <code>replicaof</code>，以独立主库身份运行</td><td>检查旧主库的 <code>INFO replication</code> 角色</td></tr><tr><td>新主库不可写</td><td><code>replica-read-only</code> 没取消，或 <code>REPLICAOF NO ONE</code> 没成功</td><td>在新主库上执行写入测试</td></tr></tbody></table><p>旧主库恢复后的处理是容易出问题的环节——如果直接启动但没有配置 <code>replicaof</code>，它就成为一个独立主库。此时系统中存在两个&quot;主库&quot;，各自接受写入，数据出现分叉。恢复旧主库的正确方式是让它以从库身份加入，挂到新主库下面。</p><h2 id="十、通知脚本" tabindex="-1">十、通知脚本 <a class="header-anchor" href="#十、通知脚本" aria-label="Permalink to &quot;十、通知脚本&quot;">​</a></h2><p>Sentinel 可以在发生关键事件时执行外部脚本：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sentinel notification-script mymaster /usr/local/bin/redis-sentinel-notify.sh</span></span></code></pre></div><p>脚本示例：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/bin/bash</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -euo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pipefail</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">event</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">master</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">logger</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-sentinel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;event=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$event</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> master=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$master</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> args=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>脚本里不适合写太重的逻辑——调外部 API 失败或执行时间过长会影响 Sentinel 自身工作。更稳妥的做法是脚本只记录和投递事件（发一条消息到监控系统），复杂处理交给外部系统。</p><h2 id="十一、常见故障排查" tabindex="-1">十一、常见故障排查 <a class="header-anchor" href="#十一、常见故障排查" aria-label="Permalink to &quot;十一、常见故障排查&quot;">​</a></h2><p><strong>主库故障但没有切换</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 看有多少 Sentinel 在线</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 26379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SENTINEL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sentinels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mymaster</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 看主库在 Sentinel 眼中的状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 26379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SENTINEL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> master</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mymaster</span></span></code></pre></div><p>常见原因：Sentinel 节点之间不通（无法形成 ODOWN）、quorum 设置太高凑不够票、所有从库的 <code>replica-priority</code> 都是 0、或者 Sentinel 和主库之间的网络没断但主库和客户端之间断了（Sentinel 角度看主库还活着）。</p><p><strong>Sentinel 看不到从库</strong>：从库的 <code>replicaof</code> 配置是否正确、从库和 Sentinel 之间的网络可达性、<code>sentinel auth-pass</code> 密码是否正确。</p><p><strong>切换后应用报错</strong>：十有八九是客户端没接 Sentinel，或者连接池没刷新。</p><p>Sentinel 是主从架构上的自动切换组件，不是完整高可用方案的全部。应用连接、网络隔离、监控告警、旧主库恢复流程，这些缺一个都会让自动切换的效果大打折扣。</p>`,68)])])}const E=i(e,[["render",l]]);export{c as __pageData,E as default};
